    function getGreeting(customDate) {
      const now = customDate ? new Date(customDate) : new Date();
      const hour = now.getHours();
      if (hour >= 6 && hour < 12) {
        return "Bom dia,";
      } else if (hour >= 12 && hour < 18) {
        return "Boa tarde,";
      } else {
        return "Boa noite,";
      }
    }
